ControlPropertyState.AutoRuleBindingString:
If(
    IsBlank(operatorName.SelectedText),
    Notify("Please Select your nmae", NotificationType.Error),
    IsBlank(cncDrop.Selected.Value),
    Notify("Please Enter in Machine Number", NotificationType.Error),
    coolUnit.Value = false ||
    lubUnit.Value = false ||
    oilAirLub.Value = false ||
    machineCham.Value = false ||
    chuck.Value = false ||
    obsWindow.Value = false ||
    pneuDev.Value = false ||
    chipConv.Value = false ||
    oilChill.Value = false ||
    hydraUnit.Value = false,


    /* If any checkbox is false, navigate to a new screen */
    Navigate(popUpScreen),

    /* If all checkboxes are checked, execute the following code */
    Patch(
        'CNC Pre-Use/Daily Checklist',
        Defaults('CNC Pre-Use/Daily Checklist'),
        {
            'CNC/Operator': operatorName.Selected.'Employee Name',
            'Lubricating Unit - Look/Clean': lubUnit.Value,
            'Oil Air Lubricating Unit': oilAirLub.Value,
            'Machine Chamber - clean': machineCham.Value,
            'Chuck - clean/warmup/grease': chuck.Value,
            'Observation Window - clean': obsWindow.Value,
            'Pneumatic Device - look/checks': pneuDev.Value,
            'Coolant Unit - look/check': coolUnit.Value,
            'Chip Conveyors - clean': chipConv.Value,
            'Oil Chiller - look/clean': oilChill.Value,
            'Hydraulic Unit - look/clean': hydraUnit.Value,
            'Machine Number': cncDrop.Selected.Value,
            Notes: noteInput.Text

        }
    );

    Notify("Form Successfully Updated", NotificationType.Success);

    /* Reset controls after Patch operation */
    Reset(chipConv);
    Reset(oilChill);
    Reset(chipConv);
    Reset(coolUnit);
    Reset(lubUnit);
    Reset(chuck);
    Reset(machineCham);
    Reset(obsWindow);
    Reset(pneuDev);
    Reset(oilAirLub);
    Reset(noteInput);
    Reset(hydraUnit);
    Reset(cncDrop);
    Reset(operatorName);
    Navigate(homeScreen)
)
